import{_ as a,o as r,c as d,a2 as e}from"./chunks/framework.xcumbC7K.js";const g=JSON.parse('{"title":"为什么选择 NovaChart？","description":"","frontmatter":{},"headers":[],"relativePath":"guide/why-nova-chart.md","filePath":"guide/why-nova-chart.md","lastUpdated":1781997983000}'),o={name:"guide/why-nova-chart.md"};function i(l,t,n,h,s,u){return r(),d("div",null,[...t[0]||(t[0]=[e('<h1 id="为什么选择-novachart" tabindex="-1">为什么选择 NovaChart？ <a class="header-anchor" href="#为什么选择-novachart" aria-label="Permalink to &quot;为什么选择 NovaChart？&quot;">​</a></h1><h2 id="与-chart-js-对比" tabindex="-1">与 Chart.js 对比 <a class="header-anchor" href="#与-chart-js-对比" aria-label="Permalink to &quot;与 Chart.js 对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>Chart.js v4</th><th>NovaChart</th></tr></thead><tbody><tr><td>源码行数</td><td>11,589</td><td><strong>628</strong></td></tr><tr><td>打包后体积</td><td>~200KB</td><td><strong>18KB</strong></td></tr><tr><td>API 字段数</td><td>30+</td><td><strong>8</strong></td></tr><tr><td>图表类型</td><td>8 种</td><td><strong>4 种</strong></td></tr><tr><td>坐标轴</td><td>6 种</td><td><strong>2 种</strong></td></tr><tr><td>主题</td><td>自行配置</td><td><strong>3 套开箱</strong></td></tr><tr><td>动画</td><td>完整引擎</td><td><strong>3 种基础</strong></td></tr><tr><td>学习成本</td><td>数小时</td><td><strong>5 分钟</strong></td></tr></tbody></table><h2 id="设计取舍" tabindex="-1">设计取舍 <a class="header-anchor" href="#设计取舍" aria-label="Permalink to &quot;设计取舍&quot;">​</a></h2><h3 id="我们砍掉了什么" tabindex="-1">我们砍掉了什么？ <a class="header-anchor" href="#我们砍掉了什么" aria-label="Permalink to &quot;我们砍掉了什么？&quot;">​</a></h3><table tabindex="0"><thead><tr><th>砍掉的功能</th><th>理由</th></tr></thead><tbody><tr><td>Bubble / Scatter / Radar / PolarArea</td><td>学生用不上 90% 的场景</td></tr><tr><td>Doughnut（只保留 Pie）</td><td>Doughnut 视觉效果与 Pie 重复</td></tr><tr><td>Logarithmic / Time / RadialLinear 坐标轴</td><td>学术场景，初学不需要</td></tr><tr><td>多数据集（datasets: [...]）</td><td>引入后 API 复杂度翻倍</td></tr><tr><td>缩放 / 拖拽 / 平移</td><td>静态展示足够</td></tr><tr><td>Tree-shaking 注册机制</td><td>学生不会按需引入</td></tr><tr><td>TypeScript 类型定义</td><td>v1 暂不提供</td></tr><tr><td>复杂动画引擎</td><td>fade / slide 覆盖 95% 效果</td></tr></tbody></table><h3 id="我们保留了什么" tabindex="-1">我们保留了什么？ <a class="header-anchor" href="#我们保留了什么" aria-label="Permalink to &quot;我们保留了什么？&quot;">​</a></h3><ul><li>✅ 4 种最常用图表：Bar / Line / Pie / Table</li><li>✅ 2 种坐标轴：Category（分类）/ Linear（数值）</li><li>✅ 3 套主题：ocean / sunset / dark</li><li>✅ 3 种动画：fade / slide / none</li><li>✅ Canvas 高质量渲染（抗锯齿）</li><li>✅ 响应式：自适应父容器宽度</li><li>✅ 主题色联动：网格 / 文字 / 表格 / 图表</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><h3 id="👍-推荐使用" tabindex="-1">👍 推荐使用 <a class="header-anchor" href="#👍-推荐使用" aria-label="Permalink to &quot;👍 推荐使用&quot;">​</a></h3><ul><li>🎓 <strong>学生</strong>：作业、毕设、网页作品</li><li>🐍 <strong>Python 用户</strong>：想在网页展示数据但不想学前端</li><li>🚀 <strong>快速原型</strong>：5 分钟内出图</li><li>📊 <strong>静态报告</strong>：不需要交互的可视化</li></ul><h3 id="👎-不推荐使用" tabindex="-1">👎 不推荐使用 <a class="header-anchor" href="#👎-不推荐使用" aria-label="Permalink to &quot;👎 不推荐使用&quot;">​</a></h3><ul><li>💼 商业级数据大屏（用 ECharts / AntV）</li><li>🔬 复杂学术图表（用 D3 / Plotly）</li><li>📱 需要手势交互的移动端可视化</li><li>🏢 企业级 BI 工具（用 Highcharts）</li></ul><h2 id="一句话总结" tabindex="-1">一句话总结 <a class="header-anchor" href="#一句话总结" aria-label="Permalink to &quot;一句话总结&quot;">​</a></h2><blockquote><p><strong>如果你只想&quot;画个图&quot;，用 NovaChart。</strong><br><strong>如果你想&quot;画好图&quot;，用 Chart.js / ECharts。</strong><br><strong>如果你想&quot;画奇葩的图&quot;，用 D3。</strong></p></blockquote>',15)])])}const b=a(o,[["render",i]]);export{g as __pageData,b as default};
